import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.CHSDihme.js";const i="/claude-code-token-free/assets/01-memory-overview.BLhQzocq.png",o="/claude-code-token-free/assets/02-memory-types.BqWicYEF.png",r="/claude-code-token-free/assets/03-memory-trigger.DbOhjneA.png",l="/claude-code-token-free/assets/04-memory-lifecycle.C5uE657y.png",y=JSON.parse('{"title":"Claude Code Memory System — Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/memory/01-usage-guide.md","filePath":"en/memory/01-usage-guide.md","lastUpdated":1780310741000}'),d={name:"en/memory/01-usage-guide.md"};function p(c,e,h,m,u,g){return s(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="claude-code-memory-system--usage-guide" tabindex="-1">Claude Code Memory System — Usage Guide <a class="header-anchor" href="#claude-code-memory-system--usage-guide" aria-label="Permalink to &quot;Claude Code Memory System — Usage Guide&quot;">​</a></h1><blockquote><p>Let Claude Code remember who you are, what you prefer, and what&#39;s happening in your project across sessions.</p></blockquote><p align="center"><a href="#1-what-is-the-memory-system">Memory System</a> · <a href="#2-four-memory-types">Four Memory Types</a> · <a href="#3-how-to-trigger-memory-saving">Trigger Saving</a> · <a href="#4-where-are-memories-stored">Storage Location</a> · <a href="#5-how-to-manage-memories">Manage Memories</a> · <a href="#6-memory-lifecycle">Lifecycle</a> · <a href="#7-quick-reference">Quick Reference</a></p><p><img src="'+i+'" alt="Memory System Overview"></p><hr><h2 id="1-what-is-the-memory-system" tabindex="-1">1. What Is the Memory System? <a class="header-anchor" href="#1-what-is-the-memory-system" aria-label="Permalink to &quot;1. What Is the Memory System?&quot;">​</a></h2><p>Claude Code&#39;s memory system is a <strong>file-based persistent knowledge store</strong> that allows Claude to continuously build understanding of you and your project across multiple conversations.</p><p>Core principle: <strong>Only remember things that cannot be inferred from the code itself.</strong></p><table tabindex="0"><thead><tr><th>Remembered</th><th>Not Remembered</th></tr></thead><tbody><tr><td>You&#39;re a data scientist focused on logging systems</td><td>Code architecture, file structure</td></tr><tr><td>&quot;Don&#39;t mock the database&quot;</td><td>Git history, who changed what</td></tr><tr><td>Non-critical merges frozen after Thursday</td><td>Existing CLAUDE.md content</td></tr><tr><td>Bug tracking is in Linear&#39;s INGEST project</td><td>Debugging solutions (fixes are already in the code)</td></tr></tbody></table><hr><h2 id="2-four-memory-types" tabindex="-1">2. Four Memory Types <a class="header-anchor" href="#2-four-memory-types" aria-label="Permalink to &quot;2. Four Memory Types&quot;">​</a></h2><p><img src="'+o+`" alt="Four Memory Types"></p><p>Claude Code strictly categorizes memories into four types:</p><h3 id="21-user-user-profile" tabindex="-1">2.1 User (User Profile) <a class="header-anchor" href="#21-user-user-profile" aria-label="Permalink to &quot;2.1 User (User Profile)&quot;">​</a></h3><p>Records your role, goals, skill level, and preferences to help Claude tailor its collaboration approach.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User says: I&#39;ve written Go for ten years, but this is my first time touching the React part of this repo</span></span>
<span class="line"><span>Claude saves: Deep Go experience, React newcomer — explain frontend concepts using backend analogies</span></span></code></pre></div><h3 id="22-feedback-behavioral-feedback" tabindex="-1">2.2 Feedback (Behavioral Feedback) <a class="header-anchor" href="#22-feedback-behavioral-feedback" aria-label="Permalink to &quot;2.2 Feedback (Behavioral Feedback)&quot;">​</a></h3><p>Your corrections or affirmations about how Claude works. These memories prevent Claude from repeating the same mistakes.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User says: Don&#39;t summarize what you did at the end of your reply, I can see the diff</span></span>
<span class="line"><span>Claude saves: User prefers concise replies, no trailing summaries</span></span></code></pre></div><p><strong>Important</strong>: Not only corrections are recorded -- affirmations are too. If Claude makes a non-obvious choice and you approve, that gets remembered as well.</p><h3 id="23-project-project-context" tabindex="-1">2.3 Project (Project Context) <a class="header-anchor" href="#23-project-project-context" aria-label="Permalink to &quot;2.3 Project (Project Context)&quot;">​</a></h3><p>Project context that cannot be derived from the code or Git history: who&#39;s doing what, why, and deadlines.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User says: We&#39;re freezing all non-critical merges after Thursday, the mobile team needs to cut a release branch</span></span>
<span class="line"><span>Claude saves: Merge freeze starting 2026-03-05, flag non-critical PR work after this date</span></span></code></pre></div><p><strong>Note</strong>: Claude converts relative dates (&quot;Thursday&quot;) to absolute dates (&quot;2026-03-05&quot;) to ensure memories don&#39;t become ambiguous over time.</p><h3 id="24-reference-external-references" tabindex="-1">2.4 Reference (External References) <a class="header-anchor" href="#24-reference-external-references" aria-label="Permalink to &quot;2.4 Reference (External References)&quot;">​</a></h3><p>Pointers to information in external systems: dashboards, issue trackers, Slack channels.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User says: On-call monitors the grafana.internal/d/api-latency dashboard</span></span>
<span class="line"><span>Claude saves: grafana.internal/d/api-latency is the on-call latency dashboard — check when editing request path code</span></span></code></pre></div><hr><h2 id="3-how-to-trigger-memory-saving" tabindex="-1">3. How to Trigger Memory Saving <a class="header-anchor" href="#3-how-to-trigger-memory-saving" aria-label="Permalink to &quot;3. How to Trigger Memory Saving&quot;">​</a></h2><p><img src="`+r+`" alt="Memory Trigger Flow"></p><h3 id="method-1-automatic-extraction-most-common" tabindex="-1">Method 1: Automatic Extraction (Most Common) <a class="header-anchor" href="#method-1-automatic-extraction-most-common" aria-label="Permalink to &quot;Method 1: Automatic Extraction (Most Common)&quot;">​</a></h3><p>This is the primary method. <strong>You don&#39;t need to do anything</strong> -- Claude automatically analyzes conversation content at the end of each conversation turn and extracts information worth remembering.</p><p>Workflow:</p><ol><li>You have a normal conversation with Claude</li><li>Claude finishes its response (no tool calls pending)</li><li>A <strong>memory extraction sub-agent</strong> starts in the background</li><li>The sub-agent analyzes the recent conversation content</li><li>It identifies memories worth saving</li><li>Writes memory files + updates the MEMORY.md index</li></ol><p>The terminal will display a notification:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Memory updated in ~/.claude/projects/.../memory/feedback_testing.md · /memory to edit</span></span></code></pre></div><h3 id="method-2-explicit-request" tabindex="-1">Method 2: Explicit Request <a class="header-anchor" href="#method-2-explicit-request" aria-label="Permalink to &quot;Method 2: Explicit Request&quot;">​</a></h3><p>Directly tell Claude to &quot;remember this&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: Remember, this project must run bun test before deploying</span></span>
<span class="line"><span>Claude: [Immediately saves as a feedback-type memory]</span></span></code></pre></div><h3 id="method-3-memory-command" tabindex="-1">Method 3: /memory Command <a class="header-anchor" href="#method-3-memory-command" aria-label="Permalink to &quot;Method 3: /memory Command&quot;">​</a></h3><p>Type <code>/memory</code> in the terminal to open a file picker that lets you edit memory files directly in your editor.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /memory</span></span></code></pre></div><p>This lists all editable memory files (CLAUDE.md, CLAUDE.local.md, auto-memory, etc.) and opens the selected file with your <code>$EDITOR</code> or <code>$VISUAL</code>.</p><h3 id="method-4-remember-command" tabindex="-1">Method 4: /remember Command <a class="header-anchor" href="#method-4-remember-command" aria-label="Permalink to &quot;Method 4: /remember Command&quot;">​</a></h3><p>Type <code>/remember</code> to trigger the memory review skill, which will:</p><ul><li>Review all automatic memory entries</li><li>Propose promoting suitable entries to CLAUDE.md or CLAUDE.local.md</li><li>Detect duplicate, outdated, and conflicting memories</li><li><strong>Does not modify anything directly</strong> -- all changes require your approval</li></ul><hr><h2 id="4-where-are-memories-stored" tabindex="-1">4. Where Are Memories Stored? <a class="header-anchor" href="#4-where-are-memories-stored" aria-label="Permalink to &quot;4. Where Are Memories Stored?&quot;">​</a></h2><h3 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/</span></span>
<span class="line"><span>└── projects/</span></span>
<span class="line"><span>    └── {project-path-hash}/</span></span>
<span class="line"><span>        └── memory/                    &lt;- Auto-memory directory</span></span>
<span class="line"><span>            ├── MEMORY.md              &lt;- Index file (always loaded into context)</span></span>
<span class="line"><span>            ├── user_role.md           &lt;- User profile memory</span></span>
<span class="line"><span>            ├── feedback_testing.md    &lt;- Behavioral feedback memory</span></span>
<span class="line"><span>            ├── project_freeze.md      &lt;- Project context memory</span></span>
<span class="line"><span>            ├── reference_linear.md    &lt;- External reference memory</span></span>
<span class="line"><span>            └── team/                  &lt;- Team shared memory (if enabled)</span></span>
<span class="line"><span>                ├── MEMORY.md</span></span>
<span class="line"><span>                └── ...</span></span></code></pre></div><h3 id="memory-file-format" tabindex="-1">Memory File Format <a class="header-anchor" href="#memory-file-format" aria-label="Permalink to &quot;Memory File Format&quot;">​</a></h3><p>Each memory file uses YAML frontmatter + Markdown content:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Testing strategy preference</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Integration tests must use a real database, no mocking</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">feedback</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integration tests must use a real database, no mocking.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Why:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Last quarter, mocked tests passed but production migrations failed — mock/production divergence masked the issues.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**How to apply:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> When writing or reviewing tests, ensure database operations use real connections.</span></span></code></pre></div><h3 id="memorymd-index-file" tabindex="-1">MEMORY.md Index File <a class="header-anchor" href="#memorymd-index-file" aria-label="Permalink to &quot;MEMORY.md Index File&quot;">​</a></h3><p>MEMORY.md is an index, not content. It is <strong>always loaded into context</strong>, with one entry per line:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">User role</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">user_role.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) — Data scientist, focused on observability/logging</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Testing strategy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">feedback_testing.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) — Integration tests use real DB, no mocking</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Merge freeze</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">project_freeze.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) — Non-critical merges frozen starting 2026-03-05</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">Bug tracking</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">reference_linear.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) — Pipeline bugs tracked in Linear INGEST project</span></span></code></pre></div><p><strong>Limit</strong>: Maximum 200 lines or 25KB; content beyond this is truncated.</p><hr><h2 id="5-how-to-manage-memories" tabindex="-1">5. How to Manage Memories <a class="header-anchor" href="#5-how-to-manage-memories" aria-label="Permalink to &quot;5. How to Manage Memories&quot;">​</a></h2><h3 id="ask-claude-to-forget" tabindex="-1">Ask Claude to Forget <a class="header-anchor" href="#ask-claude-to-forget" aria-label="Permalink to &quot;Ask Claude to Forget&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: Forget the memory about the merge freeze</span></span>
<span class="line"><span>Claude: [Finds and deletes the relevant memory file and index entry]</span></span></code></pre></div><h3 id="ask-claude-to-ignore-memories" tabindex="-1">Ask Claude to Ignore Memories <a class="header-anchor" href="#ask-claude-to-ignore-memories" aria-label="Permalink to &quot;Ask Claude to Ignore Memories&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: Ignore memories, start from scratch</span></span>
<span class="line"><span>Claude: [Does not use any memory content in this conversation]</span></span></code></pre></div><h3 id="manual-editing" tabindex="-1">Manual Editing <a class="header-anchor" href="#manual-editing" aria-label="Permalink to &quot;Manual Editing&quot;">​</a></h3><p>Directly edit files under <code>~/.claude/projects/{hash}/memory/</code>, or use the <code>/memory</code> command.</p><h3 id="disable-automatic-memory" tabindex="-1">Disable Automatic Memory <a class="header-anchor" href="#disable-automatic-memory" aria-label="Permalink to &quot;Disable Automatic Memory&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>How</th></tr></thead><tbody><tr><td>Environment variable</td><td><code>CLAUDE_CODE_DISABLE_AUTO_MEMORY=1</code></td></tr><tr><td>Settings file</td><td>Set <code>&quot;autoMemoryEnabled&quot;: false</code> in <code>settings.json</code></td></tr><tr><td>Bare mode</td><td>Start with <code>--bare</code> / <code>CLAUDE_CODE_SIMPLE=1</code></td></tr></tbody></table><h3 id="custom-memory-directory" tabindex="-1">Custom Memory Directory <a class="header-anchor" href="#custom-memory-directory" aria-label="Permalink to &quot;Custom Memory Directory&quot;">​</a></h3><p>Set in <code>~/.claude/settings.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;autoMemoryDirectory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~/my-claude-memories&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Supports <code>~/</code> expansion. For security reasons, the project-level <code>.claude/settings.json</code> is <strong>not allowed</strong> to set this option.</p><hr><h2 id="6-memory-lifecycle" tabindex="-1">6. Memory Lifecycle <a class="header-anchor" href="#6-memory-lifecycle" aria-label="Permalink to &quot;6. Memory Lifecycle&quot;">​</a></h2><p><img src="`+l+`" alt="Memory Lifecycle"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>New information learned during conversation</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span> Auto-extraction / Explicit save</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>  Write memory file + index</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span> Next conversation loads MEMORY.md</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>  Intelligent selection of relevant memories (Sonnet)</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>   Inject into conversation context</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>  Memory getting old? Verify before using</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>  Outdated? Update or delete</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span> (After 24h + 5 sessions)</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>  AutoDream consolidates memories in background</span></span></code></pre></div><h3 id="autodream----dreaming-to-organize-memories" tabindex="-1">AutoDream -- &quot;Dreaming&quot; to Organize Memories <a class="header-anchor" href="#autodream----dreaming-to-organize-memories" aria-label="Permalink to &quot;AutoDream -- &quot;Dreaming&quot; to Organize Memories&quot;">​</a></h3><p>Claude Code has a hidden <strong>AutoDream</strong> feature, analogous to how the human brain organizes memories during sleep. When the following conditions are met, Claude silently launches a &quot;dreaming&quot; sub-agent in the background:</p><ul><li>At least <strong>&gt;= 24 hours</strong> since the last consolidation</li><li>At least <strong>&gt;= 5 sessions</strong> accumulated in the interim</li></ul><p>The dreaming process has four phases: Orient -&gt; Gather -&gt; Consolidate -&gt; Prune. The bottom status bar shows <strong>&quot;dreaming&quot;</strong>, and you can press <code>Shift+Down</code> to view progress or <code>x</code> to terminate.</p><p>For a detailed technical analysis, see <a href="./03-autodream.html">AutoDream Memory Consolidation</a>.</p><h3 id="freshness-management" tabindex="-1">Freshness Management <a class="header-anchor" href="#freshness-management" aria-label="Permalink to &quot;Freshness Management&quot;">​</a></h3><ul><li><strong>Today&#39;s/yesterday&#39;s memories</strong>: Used directly</li><li><strong>Memories older than 1 day</strong>: Accompanied by a stale warning, reminding Claude to verify before citing</li><li><strong>Memories referencing file paths/function names</strong>: Confirmed via grep before use to ensure they still exist</li></ul><hr><h2 id="7-quick-reference" tabindex="-1">7. Quick Reference <a class="header-anchor" href="#7-quick-reference" aria-label="Permalink to &quot;7. Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Method</th></tr></thead><tbody><tr><td>Ask Claude to remember</td><td>&quot;Remember: this project uses bun, not npm&quot;</td></tr><tr><td>Ask Claude to forget</td><td>&quot;Forget the memory about XXX&quot;</td></tr><tr><td>Edit memories</td><td><code>/memory</code> command</td></tr><tr><td>Review and organize</td><td><code>/remember</code> command</td></tr><tr><td>Ignore memories</td><td>&quot;Ignore memories&quot; / &quot;Don&#39;t use memories&quot;</td></tr><tr><td>Disable auto-memory</td><td><code>CLAUDE_CODE_DISABLE_AUTO_MEMORY=1</code></td></tr><tr><td>Disable AutoDream</td><td>Set <code>&quot;autoDreamEnabled&quot;: false</code> in <code>settings.json</code></td></tr><tr><td>Manually consolidate memories</td><td><code>/dream</code> command</td></tr><tr><td>View memory directory</td><td><code>~/.claude/projects/{hash}/memory/</code></td></tr></tbody></table>`,85)])])}const b=a(d,[["render",p]]);export{y as __pageData,b as default};
